10	// Personas is the resolver for the personas field.
11	func (r *queryResolver) Personas(ctx context.Context, projectID *string) ([]*Persona, error) {
12		loader := persona.NewPersonaLoader(r.personaProjectRoot(ctx, projectID))
13		ps, err := loader.ListPersonas()
14		if err != nil {
15			return nil, fmt.Errorf("loading personas: %w", err)
16		}
17		gql := make([]*Persona, len(ps))
18		for i, p := range ps {
19			gql[i] = personaToGQL(p)
20		}
21		return gql, nil
22	}
23	
24	// Persona is the resolver for the persona field.
25	func (r *queryResolver) Persona(ctx context.Context, name string, projectID *string) (*Persona, error) {
26		loader := persona.NewPersonaLoader(r.personaProjectRoot(ctx, projectID))
27		p, err := loader.LoadPersona(name)
28		if err != nil {
29			return nil, nil //nolint:nilerr // not-found is represented as null
30		}
31		return personaToGQL(p), nil
32	}
