34	// personaProjectRoot resolves the working directory for persona loading.
35	// When a project ID is provided, it resolves via projectRoot; otherwise
36	// falls back to the server's working directory.
37	func (r *queryResolver) personaProjectRoot(ctx context.Context, projectID *string) string {
38		if projectID != nil && *projectID != "" {
39			return r.projectRoot(ctx, *projectID)
40		}
41		return r.workingDir(ctx)
42	}
