44	// PersonaByRole is the resolver for the personaByRole field.
45	func (r *queryResolver) PersonaByRole(ctx context.Context, role string) (*Persona, error) {
46		loader := persona.NewPersonaLoader(r.workingDir(ctx))
47		ps, err := loader.FindByRole(role)
48		if err != nil || len(ps) == 0 {
49			return nil, nil
50		}
51		return personaToGQL(ps[0]), nil
52	}
