54	// Coordinators is the resolver for the coordinators field.
55	func (r *queryResolver) Coordinators(ctx context.Context) ([]*CoordinatorMetricsEntry, error) {
56		return r.State.GetCoordinatorsGraphQL(), nil
57	}
