59	// CoordinatorMetricsByProject is the resolver for the coordinatorMetricsByProject field.
60	func (r *queryResolver) CoordinatorMetricsByProject(ctx context.Context, projectRoot string) (*CoordinatorMetrics, error) {
61		return r.State.GetCoordinatorMetricsByProjectGraphQL(projectRoot), nil
62	}
