 97	// DefaultRouteStatus is the resolver for the defaultRouteStatus field.
 98	func (r *queryResolver) DefaultRouteStatus(ctx context.Context) (*DefaultRouteStatus, error) {
 99		svc, err := agent.NewServiceFromWorkDir(r.workingDir(ctx))
100		if err != nil {
101			return nil, nil //nolint:nilerr
102		}
103		dec, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{})
104		if err != nil {
105			return &DefaultRouteStatus{}, nil //nolint:nilerr
106		}
107		result := &DefaultRouteStatus{ModelRef: dec.Model}
108		if dec.Provider != "" {
109			p := dec.Provider
110			result.ResolvedProvider = &p
111		}
112		if dec.Model != "" {
113			m := dec.Model
114			result.ResolvedModel = &m
115		}
116		return result, nil
117	}
