119	// ProviderTrend is the resolver for the providerTrend field.
120	// It aggregates the sessions index into time buckets for one provider/harness
121	// and computes a projected-run-out-in-hours callout from the last-24h slope.
122	func (r *queryResolver) ProviderTrend(ctx context.Context, name string, windowDays int) (*ProviderTrend, error) {
123		name = strings.TrimSpace(name)
124		if name == "" {
125			return nil, fmt.Errorf("name required")
126		}
127		if windowDays != 7 && windowDays != 30 {
128			return nil, fmt.Errorf("windowDays must be 7 or 30")
129		}
130		now := time.Now().UTC()
131		entries := r.sessionIndexEntries(ctx)
132	
133		kind, detected := detectProviderOrHarness(ctx, r, name)
134		bucketKind := agent.MatchProvider
135		if kind == ProviderKindHarness {
136			bucketKind = agent.MatchHarness
137		}
138	
139		bucketSize := time.Hour
140		if windowDays > 7 {
141			bucketSize = 4 * time.Hour
142		}
143		buckets := agent.BucketUsage(entries, name, bucketKind, now, windowDays, bucketSize)
144		series := make([]*ProviderTrendPoint, 0, len(buckets))
145		for _, b := range buckets {
146			series = append(series, &ProviderTrendPoint{
147				BucketStart: b.Start.UTC().Format(time.RFC3339),
148				Tokens:      b.Tokens,
149				Requests:    b.Requests,
150			})
151		}
152	
153		trend := &ProviderTrend{
154			Name:       name,
155			Kind:       kind,
156			WindowDays: windowDays,
157			Series:     series,
158		}
159	
160		if detected != nil {
161			if ceiling := detected.ceilingTokens; ceiling > 0 {
162				c := ceiling
163				trend.CeilingTokens = &c
164				remaining := detected.remaining
165				if remaining < 0 {
166					remaining = ceiling - sumTailTokens(buckets, 24)
167				}
168				if p := projectRunOutHours(buckets, float64(remaining)); p > 0 {
169					trend.ProjectedRunOutHours = &p
170				}
171			}
172		}
173	
174		return trend, nil
175	}
176	
177	// --------- helpers ---------
178	
179	type detectedRow struct {
180		ceilingTokens int
181		remaining     int
182	}
183	
184	// detectProviderOrHarness looks up a name against providers first, then
185	// harnesses, returning the resolved kind and quota signal (if any).
186	func detectProviderOrHarness(ctx context.Context, r *queryResolver, name string) (ProviderKind, *detectedRow) {
187		if svc, err := agentlib.New(agentlib.ServiceOptions{}); err == nil {
188			harnesses, _ := svc.ListHarnesses(ctx)
189			for _, h := range harnesses {
190				if strings.EqualFold(h.Name, name) {
191					q := quotaFromHarnessInfo(h)
192					return ProviderKindHarness, detectedFromQuota(q)
193				}
194			}
195		}
196		if snapshots, ok, _ := agent.ConfiguredProviderSnapshots(r.workingDir(ctx)); ok {
197			for _, p := range snapshots {
198				if strings.EqualFold(p.Name, name) {
199					q := quotaFromProviderInfo(p)
200					return ProviderKindEndpoint, detectedFromQuota(q)
201				}
202			}
203		}
204		if providers, err := liveProviderInfos(ctx, r.workingDir(ctx)); err == nil {
205			for _, p := range providers {
206				if strings.EqualFold(p.Name, name) {
207					q := quotaFromProviderInfo(p)
208					return ProviderKindEndpoint, detectedFromQuota(q)
209				}
210			}
211		}
212		return ProviderKindEndpoint, nil
213	}
214	
215	func detectedFromQuota(q *ProviderQuota) *detectedRow {
216		if q == nil {
217			return nil
218		}
219		row := &detectedRow{ceilingTokens: -1, remaining: -1}
220		if q.CeilingTokens != nil {

220		if q.CeilingTokens != nil {
221			row.ceilingTokens = *q.CeilingTokens
222		}
223		if q.Remaining != nil {
224			row.remaining = *q.Remaining
225		}
226		return row
227	}
